package main

import (
	"context"
	"fmt"
	"io/ioutil"
	"os"
	"os/exec"
	"path/filepath"
	"regexp"
	"runtime"
	"strings"

	"go.skia.org/infra/go/common"
	"go.skia.org/infra/go/skerr"
	"go.skia.org/infra/go/sklog"
)

const (
	scriptHeader = `#!/bin/bash
# This file is generated by generate.go. DO NOT EDIT
set -e -x

`
)

var (
	// Edit this list when adding or removing a target platform.
	platforms = [][]string{
		{"linux", "amd64"},
		{"darwin", "amd64"},
		{"windows", "amd64"},
		{"linux", "arm64"},
	}

	scriptDir = func() string {
		_, filename, _, ok := runtime.Caller(1)
		if !ok {
			sklog.Fatal("Failed to retrieve current file path")
		}
		return filepath.Join(filepath.Dir(filename))
	}()

	toolsRegex = regexp.MustCompile(`(?m)^	_ "(.+)"$`)
)

// pkgVersions retrieves the versions of the given packages used for the given
// goos and goarch.
func pkgVersions(ctx context.Context, goos, goarch string, packages []string) ([]string, error) {
	const goListFmt = "{{if .Module}}{{if not .Module.Main}}{{.ImportPath}}{{end}}{{end}}"
	cmd := exec.CommandContext(ctx, "go", append([]string{"list", "-f", goListFmt}, packages...)...)
	cmd.Env = append(os.Environ(),
		fmt.Sprintf("GOOS=%s", goos),
		fmt.Sprintf("GOARCH=%s", goarch),
	)
	out, err := cmd.Output()
	if err != nil {
		return nil, skerr.Wrapf(err, "failed to retrieve package versions")
	}
	return strings.Split(strings.TrimSpace(string(out)), "\n"), nil
}

// writeScript writes the a script with the given contents.
func writeScript(ctx context.Context, script string, contents string) error {
	fullScriptPath := filepath.Join(scriptDir, script)
	fullScriptBytes := []byte(scriptHeader + contents)
	fmt.Println(script)
	return skerr.Wrap(ioutil.WriteFile(fullScriptPath, fullScriptBytes, 0755))
}

// writeInstallScript writes an install script.
func writeInstallScript(ctx context.Context, script, goos, goarch, action string, packages []string) error {
	contents := fmt.Sprintf("GOOS=%s GOARCH=%s go %s -v \\\n", goos, goarch, action)
	for _, pkg := range packages {
		contents += fmt.Sprintf("  %s \\\n", pkg)
	}
	contents += "  ;\n"
	return skerr.Wrap(writeScript(ctx, script, contents))
}

func main() {
	common.Init()

	ctx := context.Background()
	fmt.Println(fmt.Sprintf("Writing scripts to %s", scriptDir))

	// install-tools.sh installs tools for the current platform.
	toolsGo := filepath.Join(scriptDir, "..", "tools.go")
	b, err := ioutil.ReadFile(toolsGo)
	if err != nil {
		sklog.Fatalf("Failed to read %s: %s", toolsGo, err)
	}
	toolsPackages := []string{}
	for _, match := range toolsRegex.FindAllStringSubmatch(string(b), -1) {
		if len(match) == 2 {
			toolsPackages = append(toolsPackages, match[1])
		}
	}
	if err := writeInstallScript(ctx, "install-tools.sh", "linux", "amd64", "install", toolsPackages); err != nil {
		sklog.Fatal(err)
	}

	// Create the individual platform install scripts.
	scripts := []string{}
	for _, platformList := range platforms {
		goos := platformList[0]
		goarch := platformList[1]
		platform := fmt.Sprintf("%s-%s", goos, goarch)
		packages, err := pkgVersions(ctx, goos, goarch, []string{"all"})
		if err != nil {
			sklog.Fatalf("Failed to retrieve packages for %s: %s", platform, err)
		}
		script := fmt.Sprintf("install-%s.sh", platform)
		if err := writeInstallScript(ctx, script, goos, goarch, "install", packages); err != nil {
			sklog.Fatalf("Failed to write %s: %s", script, err)
		}
		scripts = append(scripts, script)
	}

	// Write install-all.sh.
	installAllContents := `GO_DEPS_DIR="$( cd "$(dirname "$0")" >/dev/null 2>&1 ; pwd -P )"`
	for _, script := range scripts {
		installAllContents += fmt.Sprintf("\n${GO_DEPS_DIR}/%s", script)
	}
	installAllContents += "\n"
	installAllScript := "install-all.sh"
	if err := writeScript(ctx, installAllScript, installAllContents); err != nil {
		sklog.Fatalf("Failed to write %s: %s", installAllScript, err)
	}
}
